`timescale 1ns / 1ps
//////////////////////////////////////////////////////////////////////////////////
// Self-checking testbench for the RV32IM core (module `top`).
//
// It runs the program in program.mem (generated by tools/assemble_test.py),
// captures every store via debug_data/debug_valid, and compares the sequence
// against the golden values 35, 10, 45.
//
//   PASS  -> the core's multiply, branch (signed BLT), load/store, forwarding
//            and load-use stall are all working.
//
// Run notes:
//   * program.mem and data_init.mem must be visible to the simulator's
//     working directory (in Vivado: add them to the simulation sources).
//////////////////////////////////////////////////////////////////////////////////

module tb_top;

    reg clk;
    reg rst;
    wire [31:0] debug_data;
    wire        debug_valid;

    // Device Under Test
    top dut (
        .clk(clk),
        .rst(rst),
        .debug_data(debug_data),
        .debug_valid(debug_valid)
    );

    // 100 MHz clock
    initial clk = 0;
    always #5 clk = ~clk;

    // Golden store sequence
    localparam integer N = 3;
    reg [31:0] expected [0:N-1];
    integer store_count;
    integer errors;
    integer timeout;

    initial begin
        expected[0] = 32'd35;
        expected[1] = 32'd10;
        expected[2] = 32'd45;
        store_count = 0;
        errors      = 0;

        // Reset for a few cycles (clears PC, register file, pipeline regs)
        rst = 1;
        repeat (4) @(posedge clk);
        rst = 0;

        $display("---- RV32IM core self-test ----");
    end

    // Capture stores
    always @(posedge clk) begin
        if (!rst && debug_valid) begin
            if (store_count < N) begin
                if (debug_data === expected[store_count]) begin
                    $display("[%0t] store #%0d = %0d   OK",
                              $time, store_count, debug_data);
                end else begin
                    $display("[%0t] store #%0d = %0d   EXPECTED %0d   <-- MISMATCH",
                              $time, store_count, debug_data, expected[store_count]);
                    errors = errors + 1;
                end
            end
            store_count = store_count + 1;

            if (store_count == N) begin
                #20;
                $display("--------------------------------");
                if (errors == 0 && store_count == N)
                    $display("RESULT: PASS  (all %0d stores correct)", N);
                else
                    $display("RESULT: FAIL  (errors=%0d, stores=%0d)", errors, store_count);
                $display("--------------------------------");
                $finish;
            end
        end
    end

    // Safety timeout
    initial begin
        timeout = 0;
    end
    always @(posedge clk) begin
        timeout = timeout + 1;
        if (timeout > 2000) begin
            $display("RESULT: FAIL  (timeout, only %0d/%0d stores seen)",
                      store_count, N);
            $finish;
        end
    end

endmodule
